DO $$
DECLARE
    result jsonb;
    next_value float8;
    series jsonb := '[
      {"ds": "2026-01-01", "value": 100},
      {"ds": "2026-02-01", "value": 108},
      {"ds": "2026-03-01", "value": 115},
      {"ds": "2026-04-01", "value": 123}
    ]'::jsonb;
    started timestamptz := clock_timestamp();
BEGIN
    LOOP
        SELECT rvbbit.forecast_series(series, '3') INTO result;
        EXIT WHEN result IS NOT NULL;
        IF clock_timestamp() - started > interval '2 minutes' THEN
            RAISE EXCEPTION 'forecast_series returned NULL after readiness window';
        END IF;
        PERFORM pg_sleep(2);
    END LOOP;

    IF jsonb_typeof(result) <> 'object'
       OR jsonb_typeof(result->'forecast') <> 'array'
       OR jsonb_array_length(result->'forecast') <> 3 THEN
        RAISE EXCEPTION 'unexpected forecast result: %', result;
    END IF;

    SELECT rvbbit.forecast_next_value(series) INTO next_value;
    IF next_value <= 0 THEN
        RAISE EXCEPTION 'forecast_next_value should be positive: %', next_value;
    END IF;

    WITH t(value) AS (
