    ) ON COMMIT DROP;
    INSERT INTO catalog_sql_probe VALUES
        (1, 'Alice', 'gold'),
        (2, 'Bob', 'silver');

    DELETE FROM rvbbit.receipts WHERE operator = 'catalog_sql_node_probe';
    DELETE FROM rvbbit.operators WHERE name = 'catalog_sql_node_probe';
    DROP FUNCTION IF EXISTS rvbbit.catalog_sql_node_probe(text, jsonb);

    PERFORM rvbbit.create_operator(
        op_name        => 'catalog_sql_node_probe',
        op_arg_names   => ARRAY['probe_id'],
        op_arg_types   => ARRAY['text'],
        op_return_type => 'text',
        op_shape       => 'scalar',
        op_description => 'Catalog acceptance probe for SQL and code workflow nodes.',
        op_steps       => jsonb_build_array(
            jsonb_build_object(
                'name', 'row',
                'kind', 'sql',
                'sql', 'SELECT name, tier FROM pg_temp.catalog_sql_probe WHERE id = $1::int',
                'params', jsonb_build_array('{{ inputs.probe_id }}')
            ),
            jsonb_build_object(
                'name', 'upper_name',
                'kind', 'code',
                'fn', 'uppercase',
                'inputs', jsonb_build_object('text', '{{ steps.row.output.name }}')
            )
        )
    );

    SELECT rvbbit.catalog_sql_node_probe('2') INTO out_text;
    IF out_text IS DISTINCT FROM 'BOB' THEN
        RAISE EXCEPTION 'catalog_sql_node_probe returned %, expected BOB', out_text;
    END IF;

    WITH latest AS (
        SELECT sub_calls
        FROM rvbbit.receipts
        WHERE operator = 'catalog_sql_node_probe'
        ORDER BY invocation_at DESC
        LIMIT 1
    )
    SELECT array_agg(elem->>'kind' ORDER BY ord)
    INTO kinds
    FROM latest
    CROSS JOIN LATERAL jsonb_array_elements(latest.sub_calls) WITH ORDINALITY AS e(elem, ord);

    IF kinds IS DISTINCT FROM ARRAY['sql','code']::text[] THEN
        RAISE EXCEPTION 'expected sql/code sub-calls, got %', kinds;
    END IF;

    DELETE FROM rvbbit.receipts WHERE operator = 'catalog_sql_node_probe';
    DELETE FROM rvbbit.operators WHERE name = 'catalog_sql_node_probe';
    DROP FUNCTION IF EXISTS rvbbit.catalog_sql_node_probe(text, jsonb);
EXCEPTION WHEN OTHERS THEN
    DELETE FROM rvbbit.receipts WHERE operator = 'catalog_sql_node_probe';
    DELETE FROM rvbbit.operators WHERE name = 'catalog_sql_node_probe';
    DROP FUNCTION IF EXISTS rvbbit.catalog_sql_node_probe(text, jsonb);
    RAISE;
END
$$;

DO $$
DECLARE
    v jsonb;
    latest_run uuid;
    stages text[];
BEGIN
    SELECT value
    INTO v
    FROM rvbbit.flow($q$
        select g from generate_series(1,10) g
        then limit(3)
        then count
    $q$);

    IF (v->>'n')::int IS DISTINCT FROM 3 THEN
        RAISE EXCEPTION 'flow limit/count returned %, expected {"n":3}', v;
    END IF;

    SELECT run_id
    INTO latest_run
    FROM rvbbit.flow_steps
    ORDER BY created_at DESC
    LIMIT 1;

    SELECT array_agg(stage ORDER BY step_idx)
    INTO stages
    FROM rvbbit.flow_steps
    WHERE run_id = latest_run;

    IF stages IS DISTINCT FROM ARRAY['base','limit','count']::text[] THEN
        RAISE EXCEPTION 'unexpected flow stages for %: %', latest_run, stages;
    END IF;
END
$$;

