DO $$
DECLARE
    result jsonb;
    summary text;
    started timestamptz := clock_timestamp();
BEGIN
    LOOP
        SELECT rvbbit.summarize_bart(
            'A regional warehouse delayed three outbound shipments after a scanner outage. Operations rerouted urgent orders, restored scanning after two hours, and opened a follow-up ticket for device maintenance.'
        ) INTO result;
        EXIT WHEN result IS NOT NULL;
        IF clock_timestamp() - started > interval '2 minutes' THEN
            RAISE EXCEPTION 'summarize_bart returned NULL after readiness window';
        END IF;
        PERFORM pg_sleep(2);
    END LOOP;

    IF jsonb_typeof(result) <> 'object' OR NOT (result ? 'summary_text') THEN
        RAISE EXCEPTION 'unexpected summarization shape: %', result;
    END IF;

    SELECT rvbbit.summarize_text_local(
        'A regional warehouse delayed three outbound shipments after a scanner outage. Operations rerouted urgent orders, restored scanning after two hours, and opened a follow-up ticket for device maintenance.'
    ) INTO summary;
    IF coalesce(btrim(summary), '') = '' THEN
        RAISE EXCEPTION 'summarize_text_local returned an empty summary';
    END IF;

    SELECT rvbbit.summarize_row_local(
        '{"incident":"scanner outage","impact":"three delayed outbound shipments","action":"rerouted urgent orders and opened maintenance ticket"}'::jsonb
    ) INTO summary;
    IF coalesce(btrim(summary), '') = '' THEN
        RAISE EXCEPTION 'summarize_row_local returned an empty summary';
    END IF;
END
$$;

