        END IF;
        PERFORM pg_sleep(2);
    END LOOP;

    IF jsonb_typeof(result) <> 'object'
       OR NOT (result ? 'label')
       OR NOT (result ? 'prediction') THEN
        RAISE EXCEPTION 'unexpected wine prediction shape: %', result;
